brain:
var s=context.state,a=context.action,m=context.memory;
var PI2=Math.PI*2,PI=Math.PI;
if(!m.t){m.t=0;m.d=1;}m.t++;
var angDiff=function(a,b){var d=(a-b)%PI2;if(d>PI)d-=PI2;if(d<-PI)d+=PI2;return d;};
var myX=s.position.x,myY=s.position.y,myA=s.angle;
var dC=Math.sqrt((myX-450)*(myX-450)+(myY-450)*(myY-450));
var toC=s.angleToCenter;
var rem=context.round.remaining;
var prox=s.proximity[0]||{};
var enemy=false;
for(var i=0;i<s.scanner.robot.length;i++){
  var rb=s.scanner.robot[i];
  if(rb.active&&(!enemy||rb.range<enemy.range)) enemy=rb;
}
a.desiredScan=180;
if(rem<5){
  if(dC>8){a.desiredAngle=toC;a.desiredForce=s.maxForce;}
  else a.desiredForce=0;
}else if(rem<12){
  a.desiredAngle=toC;a.desiredForce=s.maxForce;
  if(dC<40)a.desiredForce=s.maxForce*0.15;
  if(enemy)a.desiredLaunch=true;
}else{
  var targetR=200;
  if(dC>targetR+100){
    a.desiredAngle=toC;
    a.desiredForce=s.maxForce;
  }else if(dC<targetR-80){
    a.desiredAngle=toC+PI;
    a.desiredForce=s.maxForce*0.4;
  }else{
    a.desiredAngle=toC+PI/2*m.d;
    a.desiredForce=s.maxForce*0.7;
    if(Math.random()<0.008)m.d=-m.d;
  }
  if(prox.entityType=='wall'){
    a.desiredAngle=toC;a.desiredForce=s.maxForce;
  }
  if(enemy){
    var aimErr=Math.abs(angDiff(myA,enemy.angleFromRobot));
    if(aimErr<0.8)a.desiredAngle=enemy.angleFromRobot;
    a.desiredLaunch=true;
    a.desiredScan=Math.max(80,Math.min(300,enemy.range*0.8));
  }
}
if(myX<55||myX>845||myY<55||myY>845){
  a.desiredAngle=toC;a.desiredForce=s.maxForce;
}
